const lead = $input.first().json;
const errors = [];
const consent = String(lead.consent || lead.Consent || '').trim().toLowerCase();
if (!['yes', 'true', '1'].includes(consent)) errors.push('missing_or_invalid_consent');
if (!lead.full_name) errors.push('missing_full_name');
if (!lead.company_name) errors.push('missing_company_name');
if (!lead.work_email) errors.push('missing_work_email');
return [{ json: { ...lead, consent_valid: errors.length === 0, validation_errors: errors, source_record_id: lead.row_number || lead.id || $execution.id } }];

const original = $('Code - Validate Consent And Required Fields').first().json;
const raw = $input.first().json;
const content = raw.choices?.[0]?.message?.content || raw.body?.choices?.[0]?.message?.content || '{}';
let parsed;
try { parsed = typeof content === 'string' ? JSON.parse(content) : content; } catch (error) { parsed = { score: 0, tier: 'Unqualified', reasons: ['invalid_llm_json'], risk_flags: ['llm_parse_error'], recommended_next_action: 'manual review required' }; }
const score = Number(parsed.score || 0);
const tier = ['Hot', 'Warm', 'Cold', 'Unqualified'].includes(parsed.tier) ? parsed.tier : 'Unqualified';
return [{ json: { ...original, lead_score: score, lead_tier: tier, score_reasons: parsed.reasons || [], risk_flags: parsed.risk_flags || [], recommended_next_action: parsed.recommended_next_action || 'manual review required', follow_up_email_subject: parsed.follow_up_email_subject || 'Automation discovery next step', follow_up_email_body: parsed.follow_up_email_body || 'Draft requires manual review.', model_name: $env.OPENROUTER_MODEL, prompt_version: 'revops_scoring_v1' } }];
